import React, { useState, useCallback } from 'react';
import { useDropzone } from 'react-dropzone';
import { uploadFile } from '../services/api';
import { 
  Button, 
  Dialog, 
  DialogTitle, 
  DialogContent, 
  DialogActions, 
  Stack,
  LinearProgress,
  Typography,
  Box,
  Alert,
  IconButton,
  Paper
} from '@mui/material';
import CloudUploadIcon from '@mui/icons-material/CloudUpload';
import CloseIcon from '@mui/icons-material/Close';

const UploadPanel = ({ onUploadSuccess = () => {} }) => {
  const [uploading, setUploading] = useState(false);
  const [uploadStatus, setUploadStatus] = useState(null);
  const [progress, setProgress] = useState(0);
  const [error, setError] = useState(null);

  const onDrop = useCallback(async (acceptedFiles) => {
    if (acceptedFiles.length === 0) return;

    setUploading(true);
    setUploadStatus(null);
    setProgress(0);
    setError(null);

    try {
      console.log(`Starting upload of ${acceptedFiles.length} files`);

      let processed = 0;
      const results = {
        successful: [],
        failed: [],
      };

      // Process files sequentially
      for (const file of acceptedFiles) {
        try {
          // Get relative path from file if it exists (for folder upload)
          let uploadPath = '';
          if (file.path) {
            const parts = file.path.split('/');
            parts.pop(); // Remove filename
            uploadPath = parts.join('/');
          }

          console.log(`Processing file ${processed + 1}/${acceptedFiles.length}: ${file.name} to path: ${uploadPath}`);
          const result = await uploadFile(file, uploadPath);
          results.successful.push({ file: file.name, result });
        } catch (error) {
          console.error(`Failed to upload ${file.name}:`, error);
          results.failed.push({ 
            file: file.name, 
            error: error.message || 'Unknown error occurred'
          });
          setError(`Failed to upload ${file.name}: ${error.message}`);
        }

        processed++;
        setProgress((processed / acceptedFiles.length) * 100);
      }

      console.log('Final upload results:', results);
      setUploadStatus({
        successful: results.successful.length,
        failed: results.failed.map(f => `${f.file}: ${f.error}`),
        details: results
      });

      if (results.successful.length > 0) {
        onUploadSuccess();
      }
    } catch (error) {
      console.error('Upload error:', error);
      setError(error.message || 'Unknown error occurred');
      setUploadStatus({
        successful: 0,
        failed: ['Upload failed: ' + (error.message || 'Unknown error occurred')],
        details: { successful: [], failed: [{ file: 'Overall', error: error.message }] }
      });
    } finally {
      setUploading(false);
    }
  }, [onUploadSuccess]);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    noClick: uploading,
    noKeyboard: uploading,
    noDrag: uploading
  });

  const handleClose = () => {
    setUploadStatus(null);
    setError(null);
  };

  return (
    <div className="upload-panel">
      <Box sx={{ p: 3 }}>
        <Stack spacing={2} direction="column" alignItems="center">
          {error && (
            <Alert 
              severity="error" 
              onClose={() => setError(null)}
              sx={{ width: '100%', mb: 2 }}
            >
              {error}
            </Alert>
          )}

          {/* Dropzone */}
          <Paper
            {...getRootProps()}
            sx={{
              width: '100%',
              p: 3,
              textAlign: 'center',
              cursor: uploading ? 'not-allowed' : 'pointer',
              bgcolor: isDragActive ? 'action.hover' : 'background.paper',
              border: '2px dashed',
              borderColor: isDragActive ? 'primary.main' : 'divider',
              '&:hover': {
                bgcolor: 'action.hover',
              },
            }}
          >
            <input {...getInputProps()} />
            <CloudUploadIcon sx={{ fontSize: 48, color: 'primary.main', mb: 2 }} />
            <Typography variant="h6" gutterBottom>
              {uploading ? 'Uploading...' : 'Drag & drop files here'}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {isDragActive
                ? 'Drop the files here...'
                : 'or click to select files'}
            </Typography>
          </Paper>

          {/* Upload Progress */}
          {uploading && (
            <Box sx={{ width: '100%', mt: 2 }}>
              <LinearProgress variant="determinate" value={progress} />
              <Typography variant="body2" color="text.secondary" align="center" sx={{ mt: 1 }}>
                {Math.round(progress)}%
              </Typography>
            </Box>
          )}
        </Stack>
      </Box>

      {/* Results Dialog */}
      {uploadStatus && (
        <Dialog 
          open={!!uploadStatus} 
          onClose={handleClose}
          maxWidth="sm"
          fullWidth
        >
          <DialogTitle>
            Upload Results
            <IconButton
              aria-label="close"
              onClick={handleClose}
              sx={{
                position: 'absolute',
                right: 8,
                top: 8,
              }}
            >
              <CloseIcon />
            </IconButton>
          </DialogTitle>
          <DialogContent>
            <Box sx={{ py: 2 }}>
              {uploadStatus.successful > 0 && (
                <Typography variant="subtitle1" color="success.main" gutterBottom>
                  Successfully uploaded: {uploadStatus.successful} files
                </Typography>
              )}

              {/* Failed uploads */}
              {uploadStatus.failed.length > 0 && (
                <Box sx={{ mt: 2 }}>
                  <Typography variant="h6" color="error" gutterBottom>
                    Failed uploads ({uploadStatus.failed.length}):
                  </Typography>
                  <Box sx={{ 
                    maxHeight: '200px', 
                    overflowY: 'auto', 
                    border: '1px solid rgba(255, 0, 0, 0.2)',
                    borderRadius: 1,
                    p: 2,
                    bgcolor: 'rgba(255, 0, 0, 0.05)'
                  }}>
                    {uploadStatus.failed.map((error, index) => (
                      <Typography 
                        key={index} 
                        variant="body2" 
                        color="error" 
                        sx={{ 
                          mb: 1,
                          '&:last-child': { mb: 0 },
                          wordBreak: 'break-word'
                        }}
                      >
                        {error}
                      </Typography>
                    ))}
                  </Box>
                </Box>
              )}

              {/* Successful uploads */}
              {uploadStatus.details?.successful.length > 0 && (
                <Box sx={{ mt: 3 }}>
                  <Typography variant="h6" color="success.main" gutterBottom>
                    Successfully uploaded files:
                  </Typography>
                  <Box sx={{ 
                    maxHeight: '200px', 
                    overflowY: 'auto',
                    border: '1px solid rgba(0, 255, 0, 0.2)',
                    borderRadius: 1,
                    p: 2,
                    bgcolor: 'rgba(0, 255, 0, 0.05)'
                  }}>
                    {uploadStatus.details.successful.map((item, index) => (
                      <Typography 
                        key={index} 
                        variant="body2" 
                        color="success.main"
                        sx={{ 
                          mb: 1,
                          '&:last-child': { mb: 0 },
                          wordBreak: 'break-word'
                        }}
                      >
                        {item.file}
                      </Typography>
                    ))}
                  </Box>
                </Box>
              )}
            </Box>
          </DialogContent>
          <DialogActions>
            <Button onClick={handleClose}>Close</Button>
          </DialogActions>
        </Dialog>
      )}
    </div>
  );
};

export default UploadPanel;
